import { IEvent } from "@/lib/models/Event";
import EventForm from "@/components/EventForm";
import Link from "next/link";
import { notFound } from "next/navigation";
import DeleteButton from "@/components/DeleteButton";

export const dynamic = "force-dynamic";

const MOCK_EVENTS: IEvent[] = [
  {
    _id: "1",
    title: "Next.js Conference 2026",
    description: "A full-day conference covering the latest in Next.js, React Server Components, and modern web development.",
    date: "2026-04-15",
    location: "Stockholm, Sweden",
    capacity: 200,
    createdAt: new Date().toISOString(),
  },
  {
    _id: "2",
    title: "TypeScript Workshop",
    description: "Hands-on workshop for intermediate developers looking to level up their TypeScript skills.",
    date: "2026-05-02",
    location: "Gothenburg, Sweden",
    capacity: 30,
    createdAt: new Date().toISOString(),
  },
  {
    _id: "3",
    title: "MongoDB Atlas Meetup",
    description: "Learn best practices for using MongoDB Atlas in production with Node.js and Next.js apps.",
    date: "2026-05-20",
    location: "Online",
    capacity: 500,
    createdAt: new Date().toISOString(),
  },
];

async function getEvent(id: string): Promise<IEvent | null> {
  // TODO: replace with real DB call when MongoDB is connected
  // await connectDB();
  // try {
  //   const event = await Event.findById(id).lean();
  //   return event ? JSON.parse(JSON.stringify(event)) : null;
  // } catch {
  //   return null;
  // }
  return MOCK_EVENTS.find((e) => e._id === id) ?? null;
}

export default async function EventPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const event = await getEvent(id);

  if (!event) notFound();

  const formatted = new Date(event.date).toLocaleDateString("en-GB", {
    weekday: "long",
    day: "numeric",
    month: "long",
    year: "numeric",
  });

  return (
    <main className="max-w-5xl mx-auto pt-4 pb-24">
      <Link href="/" className="text-sm text-slate-400 hover:text-slate-900 transition-colors mb-8 inline-block">
        ← Back to events
      </Link>

      <div className="grid md:grid-cols-3 gap-12">
        {/* Details */}
        <div className="md:col-span-2">
          <h1 className="text-4xl font-bold text-slate-900 mb-4">{event.title}</h1>
          <p className="text-slate-500 leading-relaxed mb-8">{event.description}</p>
          <div className="flex flex-col gap-3 text-sm text-slate-500">
            <span className="flex gap-2">📅 <span>{formatted}</span></span>
            <span className="flex gap-2">📍 <span>{event.location}</span></span>
            <span className="flex gap-2">👥 <span>{event.capacity} spots available</span></span>
          </div>
        </div>

        {/* Actions + Edit */}
        <div className="space-y-6">
          <div className="border border-slate-200 rounded-xl p-6 bg-white shadow-sm">
            <h2 className="text-slate-900 font-semibold mb-4">Edit Event</h2>
            <EventForm initial={event} eventId={event._id} />
          </div>
          <DeleteButton eventId={event._id} />
        </div>
      </div>
    </main>
  );
}
